class Solution:
    def makeEqual(self, words):
        # Independent: tally per-letter counts in a fixed-size array.
        counts = [0] * 26
        for w in words:
            for ch in w:
                counts[ord(ch) - 97] += 1
        k = len(words)
        for c in counts:
            if c % k != 0:
                return False
        return True

