var makeEqual = function(words) {
    const counts = new Array(26).fill(0);
    for (const w of words) {
        for (let i = 0; i < w.length; i++) counts[w.charCodeAt(i) - 97]++;
    }
    const k = words.length;
    return counts.every(c => c % k === 0);
};
